function solve(nums1, nums0) {
    const MOD = 1000000007n;
    const n = nums1.length;

    // Each fragment is defined by (nums1[i], nums0[i]).
    // We want to order these fragments to maximize the resulting binary number.
    // A string A is "greater" than string B if, when concatenated in order,
    // the resulting number is larger.
    // This is equivalent to comparing the values of A+B vs B+A.
    // If A+B > B+A, then A should come before B.

    const fragments = [];
    for (let i = 0; i < n; i++) {
        // Store the original indices or the pair itself
        fragments.push({
            ones: nums1[i],
            zeros: nums0[i]
        });
    }

    // Custom sorting function
    // Compare fragment A and fragment B.
    // A should come before B if (A followed by B) > (B followed by A).
    const compareFragments = (A, B) => {
        // Construct the binary strings for comparison
        const strA = '1'.repeat(A.ones) + '0'.repeat(A.zeros);
        const strB = '1'.repeat(B.ones) + '0'.repeat(B.zeros);

        // Compare strA + strB vs strB + strA lexicographically (which matches numerical order for binary strings of same or different lengths, provided they are not zero).
        // Since nums1[i] + nums0[i] > 0, the strings are not empty.

        const s1 = strA + strB;
        const s2 = strB + strA;

        if (s1 > s2) {
            return -1; // A comes before B (A is "greater")
        } else if (s1 < s2) {
            return 1; // B comes before A
        } else {
            return 0;
        }
    };

    // Sort the fragments using the custom comparator
    fragments.sort(compareFragments);

    // Construct the final string by concatenating the sorted fragments
    let resultString = "";
    for (const frag of fragments) {
        resultString += '1'.repeat(frag.ones) + '0'.repeat(frag.zeros);
    }

    // Convert the binary string to a large integer modulo MOD
    // Since the total length can be up to 2*10^5, we must use modular arithmetic during conversion.

    let finalValue = 0n;
    const BigIntMOD = BigInt(MOD);

    for (let i = 0; i < resultString.length; i++) {
        const bit = resultString[i] === '1' ? 1n : 0n;
        // finalValue = (finalValue * 2 + bit) % MOD
        finalValue = (finalValue * 2n + bit) % BigIntMOD;
    }

    // Return the result as a standard number if it fits, but since the requirement is modulo 10^9+7, 
    // returning the BigInt converted to number is safest if the JS environment handles it, 
    // but since MOD < 2^53, standard number conversion should be fine for the final result.
